import{_ as a,o as i,c as s,ag as t}from"./chunks/framework.GolXoAlY.js";const d=JSON.parse('{"title":"Purpose","description":"","frontmatter":{"title":"Purpose","date":"2026-04-17T00:00:00.000Z","type":"meta","tags":["system","purpose"]},"headers":[],"relativePath":"purpose.md","filePath":"purpose.md","lastUpdated":1776444206000}'),o={name:"purpose.md"};function l(r,e,h,n,u,p){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h1><h2 id="why-this-wiki-exists" tabindex="-1">Why this wiki exists <a class="header-anchor" href="#why-this-wiki-exists" aria-label="Permalink to &quot;Why this wiki exists&quot;">​</a></h2><p>Quokka LLM Wiki 是一个面向包装设计师的四角色职业知识库。它不是答案书，而是一套持续编译、互相链接的认知网络。</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ol><li>将散落的行业资讯、案例、理论编译为可复用的知识</li><li>让包装、品牌、产品、软技能四个领域的知识互相渗透</li><li>保持与最新趋势、案例、工具链的同步</li></ol><h2 id="key-questions" tabindex="-1">Key Questions <a class="header-anchor" href="#key-questions" aria-label="Permalink to &quot;Key Questions&quot;">​</a></h2><ul><li>包装设计如何与品牌策略、用户体验形成闭环？</li><li>哪些材料、工艺、结构创新正在成为行业标准？</li><li>AI 工具如何重构设计师的工作流与决策模式？</li><li>设计师如何在专业深度与跨领域通用能力之间建立平衡？</li></ul><h2 id="research-scope" tabindex="-1">Research Scope <a class="header-anchor" href="#research-scope" aria-label="Permalink to &quot;Research Scope&quot;">​</a></h2><ul><li>包装材料与工艺（纸箱、塑料、纸缸、生物基材料）</li><li>品牌视觉与重塑（VI、Logo、包装体系、数字化）</li><li>用户体验与产品策略（市场趋势、消费行为、数据驱动）</li><li>设计师成长与工作流（习惯、工具、思维模型、系统方法）</li></ul><h2 id="evolving-thesis" tabindex="-1">Evolving Thesis <a class="header-anchor" href="#evolving-thesis" aria-label="Permalink to &quot;Evolving Thesis&quot;">​</a></h2><p>设计师的核心竞争力正从&quot;美学输出&quot;转向&quot;系统化问题解决&quot;——包装不是终点，而是品牌、用户、供应链之间的交接点。</p>',11)])])}const _=a(o,[["render",l]]);export{d as __pageData,_ as default};
